import './index.css';

import {
  useEffect,
  useState
} from 'react';

import {

  createSubject,
  getSubjects

} from '../../services/subjectService';

function SubjectManagementPage() {

  const [subjects, setSubjects] =
    useState([]);

  const [formData, setFormData] =
    useState({

      subject_name: '',
      semester: ''

    });

  // LOAD SUBJECTS
  const loadSubjects =
    async () => {

    try {

      const data =
        await getSubjects();

      console.log(data);

      setSubjects(data);

    } catch (error) {

      console.log(error);

    }

  };

  useEffect(() => {

    loadSubjects();

  }, []);

  // INPUT
  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  // SUBMIT
  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      const response =
        await createSubject(formData);

      console.log(response);

      alert(
        'Subject Created Successfully'
      );

      // CLEAR FORM
      setFormData({

        subject_name: '',
        semester: ''

      });

      // RELOAD
      loadSubjects();

    } catch (error) {

      console.log(error);

      alert(

        error.response?.data?.message ||

        error.response?.data?.error ||

        'Failed To Create Subject'

      );

    }

  };

  return (

    <div className="subject-page">

      <h1>
        Subject Management
      </h1>


      {/* FORM */}

      <form
        className="subject-form"
        onSubmit={handleSubmit}
      >

        <input
          type="text"
          name="subject_name"
          placeholder="Subject Name"
          value={formData.subject_name}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="semester"
          placeholder="Semester"
          value={formData.semester}
          onChange={handleChange}
          required
        />

        <button type="submit">

          Create Subject

        </button>

      </form>


      {/* SUBJECT LIST */}

      <div className="subject-grid">

        {

          subjects.length > 0
          ? (

            subjects.map((subject) => (

              <div
                key={subject.id}
                className="subject-card"
              >

                <h3>
                  {subject.subject_name}
                </h3>

                <p>

                  <strong>
                    Subject ID:
                  </strong>

                  {' '}

                  {subject.id}

                </p>

                <p>

                  <strong>
                    Semester:
                  </strong>

                  {' '}

                  {subject.semester}

                </p>

              </div>

            ))

          )
          : (

            <p>
              No Subjects Found
            </p>

          )

        }

      </div>

    </div>

  );

}

export default SubjectManagementPage;
